const a = [
  {"id":2825,"text":"Which of the following is correct regarding insulin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 974.","responses":[{"text":"Monomeric","correct":false,"visible":false},{"text":"Polymeric","correct":false,"visible":false},{"text":"Homodimer","correct":false,"visible":false},{"text":"Tertiary","correct":false,"visible":false},{"text":"Heterodimer","correct":true,"visible":false}]},{"id":2826,"text":"A 39-year-old man with insulin-dependent diabetes mellitus is brought to the emergency department after collapsing in a shopping mall. His blood sugar is 589 mg/dL. Which of the following preparations would have the least effect on his blood sugar level?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 755.","responses":[{"text":"Insulin glargine","correct":true,"visible":false},{"text":"NPH insulin","correct":false,"visible":false},{"text":"Insulin aspart","correct":false,"visible":false},{"text":"Insulin glulisine","correct":false,"visible":false},{"text":"Insulin lispro","correct":false,"visible":false}]},{"id":2827,"text":"Which of the following insulin preparations is used for long term, 24-hour activity?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 314-315.","responses":[{"text":"NPH insulin","correct":false,"visible":false},{"text":"Insulin glulisine","correct":false,"visible":false},{"text":"Insulin glargine","correct":true,"visible":false},{"text":"Insulin lispro","correct":false,"visible":false},{"text":"Insulin aspart","correct":false,"visible":false}]},{"id":2828,"text":"Which of the following is the most common neoplasm of the thyroid?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1084.","responses":[{"text":"Follicular carcinoma","correct":false,"visible":false},{"text":"Papillary carcinoma","correct":false,"visible":false},{"text":"Medullary carcinoma","correct":false,"visible":false},{"text":"Anaplastic (undifferentiated) carcinoma","correct":false,"visible":false},{"text":"Adenoma","correct":true,"visible":false}]},{"id":2829,"text":"Which endocrine gland is the first to develop in the embryo (at approximately 24 days after fertilization)?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 168.","responses":[{"text":"Pituitary gland","correct":false,"visible":false},{"text":"Thyroid gland","correct":true,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Parathyroid gland","correct":false,"visible":false},{"text":"Pancreas","correct":false,"visible":false}]},{"id":2830,"text":"Which of the following is incorrect regarding the mechanism of action of steroid hormones?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 920.","responses":[{"text":"They have nuclear receptors","correct":false,"visible":false},{"text":"They act on the genetic machinery of the cell","correct":false,"visible":false},{"text":"They activate transcription factors","correct":false,"visible":false},{"text":"They involve the adenylyl cyclase pathway","correct":true,"visible":false},{"text":"They have cytoplasmic receptors","correct":false,"visible":false}]},{"id":2831,"text":"Which of these is the correct dermatome for epigastric pain in acute pancreatitis?","explanation":null,"reference":null,"responses":[{"text":"T6-T10","correct":false,"visible":false},{"text":"T3-T10","correct":false,"visible":false},{"text":"T6-T8","correct":false,"visible":false},{"text":"T4-T9","correct":false,"visible":false},{"text":"T5-T10","correct":true,"visible":false}]},{"id":2836,"text":"The islets of Langerhans are developed in which month of fetal life?","explanation":"The islets of Langerhans, which are the endocrine portions of the pancreas responsible for producing and releasing hormones like insulin and glucagon, start to develop during the **third month** of fetal life.\r\n\r\nDuring fetal development, the pancreas originates from two buds, the dorsal and ventral pancreatic buds. Around the third month, these buds undergo significant growth, branching, and differentiation. The islets of Langerhans emerge as clusters of specialized endocrine cells within the pancreatic tissue.\r\n\r\nThese islets continue to mature and develop throughout fetal life and postnatally. The proper development and function of the islets of Langerhans are crucial for regulating blood glucose levels and maintaining overall glucose homeostasis in the body.","reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 244.","responses":[{"text":"Fifth month","correct":false,"visible":false},{"text":"Third month","correct":true,"visible":false},{"text":"Sixth month","correct":false,"visible":false},{"text":"Second month","correct":false,"visible":false},{"text":"Fourth month","correct":false,"visible":false}]},{"id":2837,"text":"A 20-year-old man was brought to the emergency room presenting with seizures, paresthesia, cramps, and tetany. After managing his symptoms, his blood calcium levels were investigated and were found to be lower than normal. The doctor explained to the patient's attendant that he had a disease that was caused by the deficiency of a specific hormone. What is the most common cause of this condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1096.","responses":[{"text":"Surgical","correct":true,"visible":false},{"text":"Congenital","correct":false,"visible":false},{"text":"Neoplasia","correct":false,"visible":false},{"text":"Autoimmune","correct":false,"visible":false},{"text":"Idiopathic","correct":false,"visible":false}]},{"id":2838,"text":"All catecholamines are derived from which of the following amino acids?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 285.","responses":[{"text":"Valine","correct":false,"visible":false},{"text":"Tyrosine","correct":true,"visible":false},{"text":"Arginine","correct":false,"visible":false},{"text":"Histidine","correct":false,"visible":false},{"text":"Tryptophan","correct":false,"visible":false}]},{"id":2850,"text":"Which of these regarding the steroid hormones is correct?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 920.","responses":[{"text":"cAMP","correct":false,"visible":false},{"text":"IP3","correct":false,"visible":false},{"text":"Receptor tyrosine kinase","correct":false,"visible":false},{"text":"Intracellular receptor","correct":true,"visible":false},{"text":"cGMP","correct":false,"visible":false}]},{"id":2851,"text":"Which of the following is true regarding the growth hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 931.","responses":[{"text":"It decreases the concentration of glucose and free fatty acids","correct":false,"visible":false},{"text":"It is synthesized and stored in the posterior pituitary gland","correct":false,"visible":false},{"text":"It is a catabolic hormone","correct":false,"visible":false},{"text":"It has 191 amino acids","correct":true,"visible":false},{"text":"It is a multi-chain polypeptide","correct":false,"visible":false}]},{"id":2852,"text":"What is the recommended daily intake of calcium?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 399.","responses":[{"text":"500 mg","correct":false,"visible":false},{"text":"800 mg","correct":false,"visible":false},{"text":"600 mg","correct":false,"visible":false},{"text":"400 mg","correct":false,"visible":false},{"text":"1,000 mg","correct":true,"visible":false}]},{"id":2853,"text":"What is the percentage of body calcium stored in teeth and bones?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 991.","responses":[{"text":"85%","correct":false,"visible":false},{"text":"95%","correct":false,"visible":false},{"text":"90%","correct":false,"visible":false},{"text":"80%","correct":false,"visible":false},{"text":"99%","correct":true,"visible":false}]},{"id":2855,"text":"Cytokines can act as which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 915.","responses":[{"text":"Paracrine + autocrine + endocrine molecules","correct":true,"visible":false},{"text":"Exocrine molecules","correct":false,"visible":false},{"text":"Paracrine molecules only","correct":false,"visible":false},{"text":"Paracrine + autocrine molecules only","correct":false,"visible":false},{"text":"Paracrine + endocrine molecules only","correct":false,"visible":false}]},{"id":2856,"text":"Which artery supplies the infundibulum?","explanation":"The **superior hypophyseal artery** supplies the infundibulum of the pituitary gland. The pituitary gland, also known as the hypophysis, is a small endocrine gland located at the base of the brain in a bony cavity called the sella turcica.\r\n\r\nThe superior hypophyseal artery is a branch of the **internal carotid artery** and is responsible for supplying blood to the upper part of the pituitary gland, which includes the infundibulum and the neural stalk that connects the hypothalamus to the pituitary gland. The infundibulum is a funnel-shaped structure that extends from the hypothalamus to the posterior lobe of the pituitary gland (neurohypophysis).","reference":"Superior hypophysial artery - an overview | sciencedirect topics. Accessed June 17, 2022. https://www.sciencedirect.com/topics/neuroscience/superior-hypophysial-artery","responses":[{"text":"External carotid artery","correct":false,"visible":false},{"text":"Superior hypophyseal artery","correct":true,"visible":false},{"text":"Internal carotid artery","correct":false,"visible":false},{"text":"Inferior hypophyseal artery","correct":false,"visible":false},{"text":"Basilar artery","correct":false,"visible":false}]},{"id":2857,"text":"A 26-year-old woman presents to the clinic due to fatigue and difficulty in breastfeeding her 5-week-old baby. She also notices a slower growth of pubic hair, constipation, weight gain, and severe fatigue. Antenatal history is unremarkable, however, she has a history of severe bleeding with blood transfusion right after her delivery. What is the diagnosis of this patient?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 159-160.","responses":[{"text":"Thyroid dysfunction","correct":false,"visible":false},{"text":"Sheehan's syndrome","correct":true,"visible":false},{"text":"Prolactinoma","correct":false,"visible":false},{"text":"MEN syndrome","correct":false,"visible":false},{"text":"Ineffective latching","correct":false,"visible":false}]},{"id":2858,"text":"Which of the following is correct regarding gene mutations responsible for parathyroid neoplasia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1129.","responses":[{"text":"GNAS mutations are responsible for familial parathyroid tumors","correct":false,"visible":false},{"text":"The most important susceptibility locus for parathyroid adenomas is the HLA gene cluster on chromosome 6p21","correct":false,"visible":false},{"text":"The mutations causing parathyroid adenomas are rarely sporadic","correct":false,"visible":false},{"text":"Cyclin D1 gene deletion leads to over-expression of cyclin D1 and thus causes parathyroid adenoma","correct":false,"visible":false},{"text":"MEN-1 mutations are responsible for parathyroid tumors","correct":true,"visible":false}]},{"id":2859,"text":"Which anterior pituitary hormone is responsible for the release of progesterone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 931.","responses":[{"text":"Adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Follicle-stimulating hormone","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Luteinizing hormone","correct":true,"visible":false},{"text":"Thyroid stimulating hormone","correct":false,"visible":false}]},{"id":2860,"text":"Which of the following is the characteristic of people with type B personality?","explanation":null,"reference":"Dow Lecture slides: Endocrinology module, Community Medicine slides, Topic: Personality, Sub-topic: Type B Personality Characteristics.","responses":[{"text":"Self centered","correct":false,"visible":false},{"text":"Competitive","correct":false,"visible":false},{"text":"Prone to heart disease","correct":false,"visible":false},{"text":"Relaxed and easy going","correct":true,"visible":false},{"text":"Aggressive","correct":false,"visible":false}]},{"id":2861,"text":"A second-year MBBS student is given a slide of an endocrine gland that contains round and oval structures lined by cuboidal epithelium. Which of the following is most likely the endocrine gland?","explanation":"The endocrine gland that contains round and oval structures lined by cuboidal epithelium is most likely the **thyroid gland**.\r\n\r\nThe thyroid gland is a bilobed endocrine gland located in the anterior neck. Each lobe of the thyroid gland is composed of numerous spherical structures known as thyroid follicles. These follicles are lined by cuboidal epithelial cells called thyroid follicular cells. The follicular cells are responsible for producing and storing thyroid hormones, mainly thyroxine (T4) and triiodothyronine (T3).\r\n\r\nThe cuboidal shape of the follicular cells and the presence of the round and oval follicles are characteristic features of the thyroid gland. These hormones play a crucial role in regulating the body's metabolism, growth, and development.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 82, 430.","responses":[{"text":"Thyroid","correct":true,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Testes","correct":false,"visible":false},{"text":"Adrenal","correct":false,"visible":false},{"text":"Pituitary","correct":false,"visible":false}]},{"id":2862,"text":"Which of the following is the most important complication of metabolic syndrome that leads to type 2 diabetes?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 447-448.","responses":[{"text":"Hypertension","correct":false,"visible":false},{"text":"Alkalosis","correct":false,"visible":false},{"text":"Hypertriglyceridemia","correct":false,"visible":false},{"text":"Acidosis","correct":false,"visible":false},{"text":"Visceral obesity","correct":true,"visible":false}]},{"id":2863,"text":"When is growth hormone released by the pituitary gland?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 933.","responses":[{"text":"After every two months","correct":false,"visible":false},{"text":"In relaxed state","correct":false,"visible":false},{"text":"In fast state","correct":false,"visible":false},{"text":"During heavy exercise","correct":true,"visible":false},{"text":"In periods of inactivity","correct":false,"visible":false}]},{"id":2876,"text":"A person with diabetes mellitus has defect in which type of pancreatic cells?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1099.","responses":[{"text":"Delta cells","correct":false,"visible":false},{"text":"Alpha cells","correct":false,"visible":false},{"text":"Beta cells","correct":true,"visible":false},{"text":"Gamma cells","correct":false,"visible":false},{"text":"PP cells","correct":false,"visible":false}]},{"id":2881,"text":"A student observes a slide of a tissue that contains secretory cells. Four types of secretory cells can be recognized in that tissue. Which organ is the tissue taken from?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427, 429.","responses":[{"text":"Head of pancreas","correct":false,"visible":false},{"text":"Tail of pancreas","correct":true,"visible":false},{"text":"Pituitary gland","correct":false,"visible":false},{"text":"Thyroid gland","correct":false,"visible":false},{"text":"Adrenal cortex","correct":false,"visible":false}]},{"id":2883,"text":"Which of the following is the most widely used method to determine obesity?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 444.\r\n\r\n(2) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 884.","responses":[{"text":"Body mass index","correct":true,"visible":false},{"text":"Blood cholesterol level","correct":false,"visible":false},{"text":"Skin thickness","correct":false,"visible":false},{"text":"Waist circumference","correct":false,"visible":false},{"text":"Waist to hip ratio","correct":false,"visible":false}]},{"id":2884,"text":"Which of the following is decreased by somatostatin?","explanation":"**Somatostatin**, also known as growth hormone-inhibiting hormone (GHIH), is a peptide hormone produced by the delta cells of the pancreas and certain other tissues in the body. It exerts inhibitory effects on various physiological processes, including the regulation of hormone secretion.\r\n\r\nOne of the main actions of somatostatin is the inhibition of the secretion of both **insulin** and **glucagon**. Insulin is a hormone produced by beta cells in the pancreas and is responsible for lowering blood glucose levels by promoting the uptake and utilization of glucose by cells. Glucagon, on the other hand, is produced by alpha cells in the pancreas and increases blood glucose levels by promoting the breakdown of glycogen into glucose and stimulating gluconeogenesis.\r\n\r\nBy inhibiting the secretion of both insulin and glucagon, somatostatin helps maintain stable blood glucose levels and prevents wide fluctuations in glucose concentration.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 983.","responses":[{"text":"Cortisol","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Both insulin and glucagon","correct":true,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false}]},{"id":2888,"text":"What shape are the follicular cells of the thyroid gland when they are highly active?","explanation":"When the follicular cells of the thyroid gland are highly active, they exhibit a **columnar** shape.\r\n\r\nThe thyroid gland is responsible for producing thyroid hormones, mainly thyroxine (T4) and triiodothyronine (T3), which play a vital role in regulating metabolism, growth, and development in the body. The synthesis and secretion of these hormones occur within the thyroid follicles.\r\n\r\nDuring periods of increased hormonal activity, such as in response to thyroid-stimulating hormone (TSH) from the pituitary gland, the follicular cells become highly active. They undergo morphological changes and become taller and more columnar in shape. This change is often observed during periods of thyroid hormone synthesis and release.\r\n\r\nThe columnar shape of the follicular cells allows for increased surface area, facilitating the uptake of iodine and the synthesis of thyroid hormones within the thyroid follicles.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 430.","responses":[{"text":"Columnar","correct":true,"visible":false},{"text":"Pseudostratified columnar","correct":false,"visible":false},{"text":"Squamous","correct":false,"visible":false},{"text":"Stratified cuboidal","correct":false,"visible":false},{"text":"Cuboidal","correct":false,"visible":false}]},{"id":2889,"text":"Congenital hypothyroidism is most commonly associated with which of the following congenital anomalies?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 169.","responses":[{"text":"Limb defects","correct":false,"visible":false},{"text":"Cleft lip and palate","correct":false,"visible":false},{"text":"Renal and ureteric anomalies","correct":true,"visible":false},{"text":"Facial abnormalities","correct":false,"visible":false},{"text":"Situs inversus","correct":false,"visible":false}]},{"id":2890,"text":"Which of the following causes vasoconstriction?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 770.","responses":[{"text":"Calcitonin","correct":false,"visible":false},{"text":"Noradrenaline","correct":true,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Melatonin","correct":false,"visible":false},{"text":"Parathyroid hormone","correct":false,"visible":false}]},{"id":2893,"text":"What process does glucagon enhance the most?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 982.","responses":[{"text":"Amino acids uptake","correct":false,"visible":false},{"text":"Hepatic glycogenolysis","correct":true,"visible":false},{"text":"Fatty acid synthesis","correct":false,"visible":false},{"text":"Protein formation","correct":false,"visible":false},{"text":"Hepatic glycogenesis","correct":false,"visible":false}]},{"id":2909,"text":"Which of the following is the most appropriate statement regarding growth and development?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 946.","responses":[{"text":"Thyroxine is required for normal growth at puberty","correct":true,"visible":false},{"text":"Linear growth ends faster in boys than girls","correct":false,"visible":false},{"text":"Growth occurs at a steady rate before puberty","correct":false,"visible":false},{"text":"Growth hormone is necessary for prenatal growth in length","correct":false,"visible":false},{"text":"Insulin-like growth factor (IGF)  decreases through childhood","correct":false,"visible":false}]},{"id":2912,"text":"Which of the following is an accurate and simple parameter, requiring no calculation, to assess central obesity?","explanation":"**Waist circumference** is an accurate and simple parameter that requires no calculation to assess central obesity. Central obesity refers to the excessive accumulation of fat in the abdominal area and is associated with an increased risk of various health conditions, including type 2 diabetes, cardiovascular diseases, and metabolic syndrome.\r\n\r\nTo measure waist circumference, a flexible measuring tape is placed around the waist, just above the hip bones. The measurement is taken at the end of normal expiration, with the tape snug but not compressing the skin.\r\n\r\nCentral obesity, as indicated by an elevated waist circumference, is an essential component of metabolic syndrome, which includes a cluster of risk factors for cardiovascular diseases and type 2 diabetes. It is a simple and valuable screening tool for identifying individuals at higher risk of obesity-related health issues.","reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 700, 744.\r\n\r\n(2) Schunkert H, Markus MRP, Stritzke J, Preedy VR. Waist circumference and cardiovascular risk. Handbook of Anthropometry: Physical Measures of Human Form in Health and Disease. Published 2012. Accessed June 20, 2022. https://doi.org/10.1007/978-1-4419-1788-1_131","responses":[{"text":"Weight measurement","correct":false,"visible":false},{"text":"Waist circumference","correct":true,"visible":false},{"text":"Blood cholesterol levels","correct":false,"visible":false},{"text":"Body mass index","correct":false,"visible":false},{"text":"Weight-to-height ratio","correct":false,"visible":false}]},{"id":2913,"text":"Screening people with positive family history for diabetes mellitus falls under which type of prevention?","explanation":null,"reference":"Kisling LA, M Das J. Prevention strategies. In: StatPearls. StatPearls Publishing; 2022. Accessed April 7, 2022. http://www.ncbi.nlm.nih.gov/books/NBK537222/","responses":[{"text":"Primordial","correct":false,"visible":false},{"text":"Secondary","correct":true,"visible":false},{"text":"Tertiary","correct":false,"visible":false},{"text":"Quaternary","correct":false,"visible":false},{"text":"Primary","correct":false,"visible":false}]},{"id":2914,"text":"Which of the following insulin preparations provides 24 hour effects?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 314-315.","responses":[{"text":"Glargine","correct":true,"visible":false},{"text":"Lispro","correct":false,"visible":false},{"text":"Aspart","correct":false,"visible":false},{"text":"Glulisine","correct":false,"visible":false},{"text":"NPH insulin","correct":false,"visible":false}]},{"id":2915,"text":"Adrenaline causes which of the following effects?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 499, 770.","responses":[{"text":"Dilation of bronchioles","correct":true,"visible":false},{"text":"Decreased heart rate","correct":false,"visible":false},{"text":"Contraction of gall bladder","correct":false,"visible":false},{"text":"Increase in intestinal motility","correct":false,"visible":false},{"text":"Decreased blood pressure","correct":false,"visible":false}]},{"id":2916,"text":"Which of the following increases the release of glucagon?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 982.","responses":[{"text":"Release of insulin","correct":false,"visible":false},{"text":"Low blood amino acid levels","correct":false,"visible":false},{"text":"Low blood glucose levels","correct":true,"visible":false},{"text":"High fatty acid concentration in blood","correct":false,"visible":false},{"text":"Period of inactivity","correct":false,"visible":false}]},{"id":2917,"text":"Which of the following are supporting cells and specialized terminal axonal endings in the posterior lobe of hypophysis?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 423.","responses":[{"text":"Lactotrophs and Howell-jolly bodies","correct":false,"visible":false},{"text":"Somatotrophs and Herring bodies","correct":false,"visible":false},{"text":"Pituicytes and Howell-jolly bodies","correct":false,"visible":false},{"text":"Lactotrophs and Herring bodies","correct":false,"visible":false},{"text":"Pituicytes and Herring bodies","correct":true,"visible":false}]},{"id":2918,"text":"Iodine uptake in thyroid cells takes place through which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 941.","responses":[{"text":"Iodide-chloride symporter","correct":false,"visible":false},{"text":"Sodium-iodide symporter","correct":true,"visible":false},{"text":"Potassium-iodide symporter","correct":false,"visible":false},{"text":"Sodium-iodide antiporter","correct":false,"visible":false},{"text":"Potassium-iodide antiporter","correct":false,"visible":false}]},{"id":2919,"text":"Craniopharyngioma is a tumor involving Rathke's pouch. Which of the following is developed from Rathke's pouch?","explanation":"Rathke's pouch is an important structure in embryonic development that gives rise to specific portions of the pituitary gland. During early embryonic life, the stomodeum invaginates to form Rathke's pouch, which eventually differentiates into two parts: the **anterior lobe (adenohypophysis)** and the **intermediate lobe** of the pituitary gland.\r\n\r\nThe **posterior lobe (neurohypophysis)** of the pituitary gland, on the other hand, originates from a downward outgrowth of the hypothalamus called the infundibulum.\r\n\r\nCraniopharyngioma is a tumor that typically arises from remnants of Rathke's pouch. It is a benign tumor that can cause various symptoms due to its location near the hypothalamus and pituitary gland. As Rathke's pouch is the origin of the **anterior lobe of the pituitary gland**, craniopharyngiomas can affect hormonal regulation and lead to endocrine disturbances.","reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 331.","responses":[{"text":"Entire pituitary gland","correct":false,"visible":false},{"text":"Posterior lobe of pituitary gland","correct":false,"visible":false},{"text":"Anterior lobe of pituitary gland","correct":true,"visible":false},{"text":"Pineal body","correct":false,"visible":false},{"text":"Hypothalamus","correct":false,"visible":false}]},{"id":2920,"text":"Which of the following is not observed in the inferior part of the hypothalamus when it is viewed from below?","explanation":"When viewed from below, the **tegmentum** is not observed in the inferior part of the hypothalamus. The tegmentum is a portion of the midbrain, specifically the ventral part, and it is located superior to the inferior part of the hypothalamus.\r\n\r\nThe other structures mentioned are observed in the inferior part of the hypothalamus when viewed from below:\r\n\r\n1. **Mammillary bodies:** These are two small, rounded structures located posterior to the hypothalamus and are involved in memory and olfactory processing.\r\n\r\n2. **Optic chiasma:** The optic chiasma is a crucial junction where the optic nerves (CN II) partially cross, just below the hypothalamus, allowing information from the left visual field to be transmitted to the right hemisphere of the brain and vice versa.\r\n\r\n3. **Infundibulum:** This is a stalk-like structure that connects the hypothalamus to the pituitary gland (hypophysis).\r\n\r\n4. **Tuber cinereum:** This is a rounded eminence in the inferior hypothalamus, situated between the mammillary bodies and the infundibulum.","reference":"Dow Lecture slides: Endocrinology module, Subject: Anatomy, Topic: Gross structure of the Hypothalamus, Sub-topic: Boundaries of Hypothalamus.","responses":[{"text":"Infundibulum","correct":false,"visible":false},{"text":"Mammillary bodies","correct":false,"visible":false},{"text":"Optic chiasma","correct":false,"visible":false},{"text":"Tuber cinereum","correct":false,"visible":false},{"text":"Tegmentum","correct":true,"visible":false}]},{"id":2921,"text":"Which of the following is the obligatory intermediate hormone which has to be first made in order to later be converted into estradiol and dihydrotestosterone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1033.","responses":[{"text":"Testosterone","correct":false,"visible":false},{"text":"Androstenedione","correct":false,"visible":false},{"text":"Pregnenolone","correct":true,"visible":false},{"text":"Dihydroxytestosterone","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false}]},{"id":2959,"text":"Which of the following stimulates the release of growth hormone (GH)?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 933.","responses":[{"text":"Insulin-like growth factor","correct":false,"visible":false},{"text":"Starvation","correct":true,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false},{"text":"Increased free fatty acid concentration","correct":false,"visible":false},{"text":"Somatostatin","correct":false,"visible":false}]},{"id":2960,"text":"Which of the following hormones causes an increase in plasma protein levels?","explanation":"**Cortisol**, also known as the stress hormone, causes an increase in plasma protein levels through its role in regulating metabolism during stressful situations. When the body is under stress, cortisol is released from the adrenal glands in response to signals from the hypothalamus and pituitary gland. \r\n\r\nCortisol has a catabolic effect on tissues, meaning it promotes the breakdown of protein and the mobilization of amino acids from muscle tissues. These amino acids are then transported to the liver, where they are used for gluconeogenesis, the process of forming glucose from non-carbohydrate sources. \r\n\r\nIn the liver, cortisol also stimulates the synthesis of acute phase proteins, including C-reactive protein, fibrinogen, and serum amyloid A. These proteins play a crucial role in the body's immune response and inflammatory processes. By increasing the production of acute phase proteins, cortisol enhances the body's ability to respond to stress and inflammation.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 963.","responses":[{"text":"Insulin","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Cortisol","correct":true,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Androgens","correct":false,"visible":false}]},{"id":2961,"text":"Growth hormone-releasing hormone (GHRH) is released by which of the following structures?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 932.","responses":[{"text":"Posterior pituitary","correct":false,"visible":false},{"text":"Melanocytes","correct":false,"visible":false},{"text":"Pineal gland","correct":false,"visible":false},{"text":"Anterior pituitary","correct":false,"visible":false},{"text":"Hypothalamus","correct":true,"visible":false}]},{"id":2962,"text":"If the growth hormone level in the blood is increased due to a tumor of the pituitary gland, then which cells of the pituitary gland are most likely affected by the tumor?","explanation":"If the growth hormone (GH) level in the blood is increased due to a tumor of the pituitary gland, the cells most likely affected by the tumor are **somatotropes**. Somatotropes are the specialized cells in the anterior pituitary gland responsible for producing and secreting growth hormone (GH or somatotropin).\r\n\r\nA tumor of the pituitary gland, specifically an adenoma, can cause excess production of GH, leading to a condition known as **acromegaly** in adults or **gigantism** in children and adolescents. Acromegaly is characterized by the enlargement of bones and tissues, particularly in the hands, feet, face, and internal organs, due to the overproduction of GH.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 930.","responses":[{"text":"Lactotropes","correct":false,"visible":false},{"text":"Thyrotropes","correct":false,"visible":false},{"text":"Somatotropes","correct":true,"visible":false},{"text":"Gonadotropes","correct":false,"visible":false},{"text":"Corticotropes","correct":false,"visible":false}]},{"id":2963,"text":"Which of the following is not a feature of Cushing syndrome?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1117.","responses":[{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Hypokalemia","correct":false,"visible":false},{"text":"Increased plasma protein levels","correct":false,"visible":false},{"text":"Hypoglycemia","correct":true,"visible":false},{"text":"Increased mobilization of fat from the lower body","correct":false,"visible":false}]},{"id":2964,"text":"Which of the following is an effect of cortisol on the immune system?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 965.","responses":[{"text":"Increases vessel permeability","correct":false,"visible":false},{"text":"Increases the rate of migration of white blood cells into the inflamed area","correct":false,"visible":false},{"text":"Increases diapedesis of white blood cells","correct":false,"visible":false},{"text":"Increases body temperature","correct":false,"visible":false},{"text":"Decreases interleukin-1 secretion","correct":true,"visible":false}]},{"id":2971,"text":"Which of the following hormones does not use cAMP as a second messenger?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"Estrogen","correct":true,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Thyroid-stimulating hormone (TSH)","correct":false,"visible":false},{"text":"Follicle-stimulating hormone (FSH)","correct":false,"visible":false}]},{"id":2974,"text":"Which of the following is the most common pituitary disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1067.","responses":[{"text":"Empty sella syndrome","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":true,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Pituitary metastatic tumors","correct":false,"visible":false},{"text":"Pituitary apoplexy","correct":false,"visible":false}]},{"id":2988,"text":"What is the action of steroid hormone when it binds to its target cell receptor?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 925.","responses":[{"text":"It causes the formation of releasing hormones","correct":false,"visible":false},{"text":"It causes the formation of cyclic AMP","correct":false,"visible":false},{"text":"It causes the formation of cyclic GMP","correct":false,"visible":false},{"text":"It is converted into cholesterol, which acts as a second messenger","correct":false,"visible":false},{"text":"It turns specific genes of the nuclear DNA on or off","correct":true,"visible":false}]},{"id":2990,"text":"The thyroid gland is lined by which type of epithelium?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 82.","responses":[{"text":"Simple squamous","correct":false,"visible":false},{"text":"Simple cuboidal","correct":true,"visible":false},{"text":"Transitional","correct":false,"visible":false},{"text":"Stratified cuboidal","correct":false,"visible":false},{"text":"Pseudostratified columnar","correct":false,"visible":false}]},{"id":2992,"text":"Which of the following substances is the precursor for all steroid hormones?","explanation":"**Cholesterol** is the precursor for all steroid hormones. It serves as the starting material from which the body synthesizes various steroid hormones, including glucocorticoids, mineralocorticoids, and sex hormones (estrogens, progesterone, and androgens).\r\n\r\nThe biosynthesis of steroid hormones begins with the conversion of cholesterol to **pregnenolone** by the enzyme cytochrome P450 side-chain cleavage enzyme (P450scc). Pregnenolone then serves as the common precursor for the synthesis of other specific steroid hormones. Depending on the tissue and the specific enzymes present, pregnenolone can be converted into different hormones.\r\n\r\nFor example, in the adrenal cortex, pregnenolone is further converted to mineralocorticoids (aldosterone) and glucocorticoids (cortisol). In the gonads (ovaries and testes), it is converted to androgens (testosterone) and estrogens (estradiol).","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 237.","responses":[{"text":"Valine","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Cholesterol","correct":true,"visible":false},{"text":"Pregnanediol","correct":false,"visible":false},{"text":"Pregnenolone","correct":false,"visible":false}]},{"id":3006,"text":"Which metabolic derangement is seen in Conn syndrome?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 415.","responses":[{"text":"Hyperkalemia","correct":false,"visible":false},{"text":"Hypercalcemia","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":true,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false}]},{"id":3007,"text":"A patient was on prednisone treatment for a long period of time. What is most likely to happen if the drug is withdrawn?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1122.","responses":[{"text":"Hemolytic anemia","correct":false,"visible":false},{"text":"Increased risk of infection","correct":false,"visible":false},{"text":"Adrenal crisis","correct":true,"visible":false},{"text":"Hyperaldosteronism","correct":false,"visible":false},{"text":"Adrenal hyperplasia","correct":false,"visible":false}]},{"id":3008,"text":"Where does the pancreatic duct start from?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 489.","responses":[{"text":"Body of the pancreas","correct":false,"visible":false},{"text":"Tail of the pancreas","correct":true,"visible":false},{"text":"Head of the pancreas","correct":false,"visible":false},{"text":"Neck of the pancreas","correct":false,"visible":false},{"text":"Uncinate process","correct":false,"visible":false}]},{"id":3010,"text":"Which of the following is accurate regarding how endocrine hormones work?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 915.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Membrane to membrane","correct":false,"visible":false},{"text":"Artery to artery","correct":false,"visible":false},{"text":"Nerve to nerve","correct":false,"visible":false},{"text":"Cell to cell","correct":true,"visible":false}]},{"id":3011,"text":"Which hormone is produced by the hypothalamic gland?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 938.","responses":[{"text":"Estradiol","correct":false,"visible":false},{"text":"Vasopressin","correct":true,"visible":false},{"text":"TSH","correct":false,"visible":false},{"text":"ACTH","correct":false,"visible":false},{"text":"FSH","correct":false,"visible":false}]},{"id":3014,"text":"Conversion of which of the following is an essential step in the formation of thyroid hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 943.","responses":[{"text":"Thyroglobulin","correct":false,"visible":false},{"text":"Thyroxine","correct":false,"visible":false},{"text":"Iodide to chloride","correct":false,"visible":false},{"text":"Iodide ions to oxidized form of iodine","correct":true,"visible":false},{"text":"Iodide to sodium iodide","correct":false,"visible":false}]},{"id":3025,"text":"Which of the following controls pituitary gland?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 930.","responses":[{"text":"Hypothalamus","correct":true,"visible":false},{"text":"Pons","correct":false,"visible":false},{"text":"Stretch receptors","correct":false,"visible":false},{"text":"Mammillary bodies","correct":false,"visible":false},{"text":"Medulla oblongata","correct":false,"visible":false}]},{"id":3027,"text":"Which of the following is secreted by the posterior pituitary gland?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Gonadotropin releasing hormone and prolactin","correct":false,"visible":false},{"text":"Growth hormone and adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Prolactin and oxytocin","correct":false,"visible":false},{"text":"Antidiuretic hormone and prolactin","correct":false,"visible":false},{"text":"Antidiuretic hormone and oxytocin","correct":true,"visible":false}]},{"id":3028,"text":"Which of the following is secreted by the paraventricular nucleus?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 938.","responses":[{"text":"Antidiuretic hormone","correct":false,"visible":false},{"text":"Oxytocin","correct":true,"visible":false},{"text":"Gonadotropin releasing hormone","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone","correct":false,"visible":false}]},{"id":3029,"text":"Which of the following hormones is a regulator of satiety?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 883.","responses":[{"text":"Cortisol","correct":false,"visible":false},{"text":"Leptin","correct":true,"visible":false},{"text":"Gastrin","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false}]},{"id":3031,"text":"Which of the following hormones causes uterine contraction?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Gonadotropin releasing hormone","correct":false,"visible":false},{"text":"Oxytocin","correct":true,"visible":false},{"text":"Adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Antidiuretic hormone","correct":false,"visible":false}]},{"id":3032,"text":"Which of the following receptors is activated by the adrenocorticotropic hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"cAMP pathway receptors","correct":true,"visible":false},{"text":"cGMP pathway receptors","correct":false,"visible":false},{"text":"Tyrosine kinase","correct":false,"visible":false},{"text":"Intracellular receptor","correct":false,"visible":false},{"text":"IP3","correct":false,"visible":false}]},{"id":3033,"text":"Tumor of which of the following cells causes secretion of excess prolactin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 931.","responses":[{"text":"Somatotropes","correct":false,"visible":false},{"text":"Corticotropes","correct":false,"visible":false},{"text":"Thyrotropes","correct":false,"visible":false},{"text":"Mammotropes","correct":true,"visible":false},{"text":"Gonadotropes","correct":false,"visible":false}]},{"id":3035,"text":"Which of the following cells secretes growth hormone (GH)?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 931.","responses":[{"text":"Somatotropes","correct":true,"visible":false},{"text":"Corticotropes","correct":false,"visible":false},{"text":"Gonadotropes","correct":false,"visible":false},{"text":"Thyrotropes","correct":false,"visible":false},{"text":"Lactotropes","correct":false,"visible":false}]},{"id":3036,"text":"Which of the following action is brought about by the activation of growth hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 935.","responses":[{"text":"Production of insulin-like growth factor","correct":true,"visible":false},{"text":"Decrease in blood sugar levels","correct":false,"visible":false},{"text":"Decrease in proliferation chondrocytes","correct":false,"visible":false},{"text":"Decrease in blood glucose levels","correct":false,"visible":false},{"text":"Decrease in fatty acids","correct":false,"visible":false}]},{"id":3037,"text":"Which of the following is the most hyperfunctioning pituitary tumor?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 159.","responses":[{"text":"Growth cell adenoma","correct":false,"visible":false},{"text":"ACTH producing adenoma","correct":false,"visible":false},{"text":"Prolactinoma","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"FSH and LH producing adenoma","correct":false,"visible":false}]},{"id":3040,"text":"Which of the following is the effect of propylthiouracil on thyroid hormone?","explanation":"Propylthiouracil (PTU) is an antithyroid drug used in the treatment of hyperthyroidism. Its primary mechanism of action involves inhibition of thyroid hormone synthesis.\r\n\r\nSpecifically, PTU exerts its effect on the thyroid gland by inhibiting two key steps in thyroid hormone synthesis:\r\n\r\n1. **Inhibition of oxidation of iodide:** The thyroid gland actively takes up iodide from the bloodstream using the sodium-iodide symporter (NIS) on the apical membrane of thyrocytes. PTU inhibits the enzyme thyroid peroxidase (TPO), which is responsible for the oxidation of iodide to iodine within the thyroid follicular cells. This inhibits the formation of iodine radicals necessary for the synthesis of thyroid hormones.\r\n\r\n2. **Inhibition of coupling of iodine:** After iodine is oxidized, it is attached to tyrosine residues on thyroglobulin, a protein within the colloid of thyroid follicles. PTU further inhibits the enzyme TPO from catalyzing the coupling of iodine residues on thyroglobulin, preventing the formation of T3 and T4 (triiodothyronine and thyroxine).","reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 308.","responses":[{"text":"Hypertrophy of thyroid follicles","correct":false,"visible":false},{"text":"Inhibit T3 release from thyroglobulin","correct":false,"visible":false},{"text":"Hyper activates Na-I symporter","correct":false,"visible":false},{"text":"Inactivates thyroglobulin","correct":false,"visible":false},{"text":"Inhibits oxidation of iodide and coupling of iodine","correct":true,"visible":false}]},{"id":3042,"text":"A student examines a histology slide having colloid surrounded by cells. Which following places are the cells extracted from?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 430.","responses":[{"text":"Hypothalamus","correct":false,"visible":false},{"text":"Thymus","correct":false,"visible":false},{"text":"Thyroid gland","correct":true,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Parathyroid gland","correct":false,"visible":false}]},{"id":3043,"text":"Which of the following is the most common cause of congenital hypothyroidism worldwide?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1077.","responses":[{"text":"Iodine deficiency","correct":true,"visible":false},{"text":"Hashimoto's thyroiditis","correct":false,"visible":false},{"text":"Autoimmune destruction","correct":false,"visible":false},{"text":"Cellular atrophy","correct":false,"visible":false},{"text":"Hypercortisolism","correct":false,"visible":false}]},{"id":3054,"text":"Which gland is regarded as the master gland?","explanation":null,"reference":"Dorton AM. The pituitary gland: embryology, physiology, and pathophysiology. Neonatal network: NN. Published March 2000. https://pubmed.ncbi.nlm.nih.gov/11949004/","responses":[{"text":"Pituitary gland","correct":true,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Thyroid gland","correct":false,"visible":false},{"text":"Pancreatic islets","correct":false,"visible":false},{"text":"Pineal gland","correct":false,"visible":false}]},{"id":3096,"text":"Where is the antidiuretic hormone synthesized?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 376.","responses":[{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Supraoptic nucleus of hypothalamus","correct":false,"visible":false},{"text":"Paraventricular nuclei of hypothalamus","correct":false,"visible":false},{"text":"Supraoptic and paraventricular nuclei of hypothalamus","correct":true,"visible":false},{"text":"Limbic system","correct":false,"visible":false}]},{"id":3098,"text":"Which of the following is the first step in the synthesis of thyroid hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 941-942.","responses":[{"text":"Iodine trapping","correct":true,"visible":false},{"text":"Organification of iodine molecules","correct":false,"visible":false},{"text":"Conjugation of tyrosine residues","correct":false,"visible":false},{"text":"Binding of thyroid hormone with thyroglobin","correct":false,"visible":false},{"text":"Formation of colloid","correct":false,"visible":false}]},{"id":3099,"text":"The accessory duct of the pancreas is formed from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 219.","responses":[{"text":"Ventral bud duct fusion with the distal part of the pancreas","correct":false,"visible":false},{"text":"Distal part of the dorsal bud","correct":false,"visible":false},{"text":"Ventral pancreatic bud","correct":false,"visible":false},{"text":"Proximal part of the dorsal bud","correct":true,"visible":false},{"text":"Proximal part of the ventral bud","correct":false,"visible":false}]},{"id":3100,"text":"A patient with excess growth hormone will have which of the following conditions?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1072.","responses":[{"text":"Lion-like facies","correct":false,"visible":false},{"text":"Gigantism after adolescence","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Acromegaly during adolescence","correct":false,"visible":false},{"text":"Acromegaly after adolescence","correct":true,"visible":false}]},{"id":3101,"text":"Which of the following will help confirm Addison's disease?","explanation":null,"reference":"Munir S, Quintanilla Rodriguez BS, Waseem M. Addison disease. In: StatPearls. StatPearls Publishing; 2022. Accessed June 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK4419","responses":[{"text":"Cortisol levels","correct":false,"visible":false},{"text":"Glucose levels","correct":false,"visible":false},{"text":"Aldosterone levels","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone levels","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone stimulation test","correct":true,"visible":false}]},{"id":3102,"text":"Which of the following is the nerve supply of the thyroid gland?","explanation":null,"reference":"Allen E, Fingeret A. Anatomy, head and neck, thyroid. In: StatPearls. StatPearls Publishing; 2022. Accessed June 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK470452/","responses":[{"text":"Mandibular nerve","correct":false,"visible":false},{"text":"Sympathetic trunk","correct":true,"visible":false},{"text":"Right recurrent laryngeal nerve","correct":false,"visible":false},{"text":"Maxillary nerve","correct":false,"visible":false},{"text":"Phrenic nerve","correct":false,"visible":false}]},{"id":3103,"text":"A 35-year-old female went to see her doctor because she had been feeling hot lately and was sweating at night. Her T3 and T4 levels were found to be high, whereas her TSH level was low. What is the most likely diagnosis made by the doctor?","explanation":"The clinical scenario described in the case is characteristic of **primary hyperthyroidism**, also known as **thyrotoxicosis**. In this condition, the thyroid gland itself is overproducing thyroid hormones (T3 and T4), leading to an increased concentration of these hormones in the bloodstream. The key laboratory findings in primary hyperthyroidism are high levels of T3 and T4 and low levels of thyroid-stimulating hormone (TSH).\r\n\r\n**Possible Causes of Primary Hyperthyroidism:**\r\n- **Graves' Disease:** An autoimmune disorder where autoantibodies stimulate the thyroid gland to produce excessive hormones.\r\n- **Toxic Multinodular Goiter:** The presence of multiple nodules in the thyroid gland, some of which are autonomously producing hormones.\r\n- **Toxic Adenoma:** A single thyroid nodule that autonomously produces excessive hormones.\r\n\r\n**Differential Diagnosis:**\r\n- **Pituitary Adenoma:** A tumor of the pituitary gland that could lead to increased TSH secretion, causing secondary hyperthyroidism.\r\n- **Secondary Hyperthyroidism:** Excessive TSH secretion from the pituitary gland, leading to increased thyroid hormone production.\r\n- **Hypothyroidism:** Low T3 and T4 levels and elevated TSH levels are characteristic of this condition.\r\n- **Myxedema:** A severe form of hypothyroidism, not applicable in this case.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 346.","responses":[{"text":"Secondary hyperthyroidism","correct":false,"visible":false},{"text":"Myxedema","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":false,"visible":false},{"text":"Primary hyperthyroidism","correct":true,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false}]},{"id":3104,"text":"Which of the following cells produce calcitonin?","explanation":"**Calcitonin** is a hormone that plays a crucial role in calcium homeostasis. It is produced and secreted by the **parafollicular cells**, also known as **C-cells**, which are specialized cells located within the thyroid gland.\r\n\r\nThe thyroid gland is primarily composed of thyroid follicles, which are spherical structures containing colloid. The thyroid follicular cells within these follicles produce and secrete the thyroid hormones, namely **thyroxine (T4)** and **triiodothyronine (T3)**.\r\n\r\nOn the other hand, the parafollicular cells are located between the thyroid follicles. These cells are responsible for synthesizing and releasing calcitonin in response to high blood calcium levels. Calcitonin acts to lower blood calcium levels by inhibiting bone resorption and enhancing calcium excretion by the kidneys.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1002.","responses":[{"text":"Parafollicular cells","correct":true,"visible":false},{"text":"Thyroid follicular cells","correct":false,"visible":false},{"text":"Chromaffin cells","correct":false,"visible":false},{"text":"Chief cells","correct":false,"visible":false},{"text":"Islets of Langerhans","correct":false,"visible":false}]},{"id":3106,"text":"Which of the following is the most common cause of hypothyroidism?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1078.","responses":[{"text":"Multinodular goiter","correct":false,"visible":false},{"text":"Follicular adenoma","correct":false,"visible":false},{"text":"Graves disease","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3108,"text":"Which of the following is a useful investigation for diagnosing Addison's disease?","explanation":null,"reference":"Munir S, Quintanilla Rodriguez BS, Waseem M. Addison disease. In: StatPearls. StatPearls Publishing; 2022. Accessed June 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK4419","responses":[{"text":"Serum cortisol","correct":false,"visible":false},{"text":"Serum electrolytes","correct":false,"visible":false},{"text":"Plasma ACTH level","correct":false,"visible":false},{"text":"Serum aldosterone","correct":false,"visible":false},{"text":"ACTH stimulation test","correct":true,"visible":false}]},{"id":3111,"text":"The principle target of aldosterone is which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 352.","responses":[{"text":"Mesangial cells","correct":false,"visible":false},{"text":"Vascular endothelium","correct":false,"visible":false},{"text":"Principal cells of the nephron","correct":true,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Carotid sinus","correct":false,"visible":false}]},{"id":3112,"text":"Which of the following is the most common disease of the thyroid in mountainous areas?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1083.","responses":[{"text":"Hashimoto's thyroiditis","correct":false,"visible":false},{"text":"Iatrogenic goiter","correct":false,"visible":false},{"text":"Myxedema","correct":false,"visible":false},{"text":"Endemic goiter","correct":true,"visible":false},{"text":"Graves disease","correct":false,"visible":false}]},{"id":3113,"text":"A patient diagnosed with acromegaly typically presents with which of the following?","explanation":"Patients with acromegaly typically present with gradual and insidious development of specific features. These include enlargement of hands and feet, coarsening of facial features, soft tissue swelling, joint pain, excessive sweating, and headaches.\r\n\r\nOne of the key metabolic abnormalities in acromegaly is **insulin resistance**. Despite increased GH promoting lipolysis, protein synthesis, and gluconeogenesis, tissues become less responsive to insulin. This results in impaired glucose uptake, leading to elevated blood glucose levels. The presence of insulin resistance may contribute to the increased risk of diabetes mellitus in patients with acromegaly.","reference":"(1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 986.\r\n\r\n(2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 335, 345.","responses":[{"text":"Decreased protein synthesis","correct":false,"visible":false},{"text":"Decreased gluconeogenesis","correct":false,"visible":false},{"text":"Decreased lipolysis","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Insulin resistance","correct":true,"visible":false}]},{"id":3119,"text":"Which of the following hormones are linked with increased bone resorption?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1117.","responses":[{"text":"Aldosterone","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Thyroid hormone","correct":false,"visible":false},{"text":"Cortisol","correct":true,"visible":false},{"text":"Melatonin","correct":false,"visible":false}]},{"id":3121,"text":"Which of the following is secreted by beta cells?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 974.","responses":[{"text":"Aldosterone","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Thyroid hormone","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Insulin","correct":true,"visible":false}]},{"id":3151,"text":"Which of the following hormone uses the adenylyl cyclase-cyclic AMP pathway?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"Parathyroid hormone","correct":true,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Thyroxine","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Testosterone","correct":false,"visible":false}]},{"id":3154,"text":"Insulin is a polypeptide. Which of the following statement is correct about insulin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 313.","responses":[{"text":"It is destroyed by gastric enzymes","correct":true,"visible":false},{"text":"It stimulates the release of glycogen","correct":false,"visible":false},{"text":"It is usually given orally","correct":false,"visible":false},{"text":"It increases gluconeogenesis","correct":false,"visible":false},{"text":"It stimulates the release of bile","correct":false,"visible":false}]},{"id":3155,"text":"Which of the following is a peptide hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Estradiol","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false},{"text":"Testosterone","correct":false,"visible":false}]},{"id":3157,"text":"While prescribing which one of the following drugs should physicians be aware that it might cause weight gain?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 345.","responses":[{"text":"Topiramate","correct":false,"visible":false},{"text":"Steroids","correct":true,"visible":false},{"text":"Fluoxetine","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Antibiotics","correct":false,"visible":false}]},{"id":3158,"text":"Oxyphil and principal cells are found in the parathyroid gland. Which of the following is a feature of oxyphil cells?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 434.","responses":[{"text":"They are arranged in small clusters","correct":true,"visible":false},{"text":"Their number decreases with age","correct":false,"visible":false},{"text":"They give rise to principal cells","correct":false,"visible":false},{"text":"They are smaller than principal cells","correct":false,"visible":false},{"text":"They have a basophilic cytoplasm","correct":false,"visible":false}]},{"id":3159,"text":"Which of the following is the confirmation test for Addison's disease?","explanation":null,"reference":"Munir S, Quintanilla Rodriguez BS, Waseem M. Addison disease. In: StatPearls. StatPearls Publishing; 2022. Accessed June 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK4419","responses":[{"text":"Aldosterone levels","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone stimulation test","correct":true,"visible":false},{"text":"Cortisol levels","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone levels","correct":false,"visible":false},{"text":"Glucose levels","correct":false,"visible":false}]},{"id":3164,"text":"Exercise stimulates the release of which of the following hormones?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 933.","responses":[{"text":"Progesterone","correct":false,"visible":false},{"text":"Thyroxine","correct":false,"visible":false},{"text":"Growth hormone","correct":true,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Parathyroid hormone","correct":false,"visible":false}]},{"id":3169,"text":"Which of the following statement is incorrect regarding the pancreas?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 334.","responses":[{"text":"Acinar cells have zymogen granules","correct":false,"visible":false},{"text":"Intercalated ducts have centroacinar cells","correct":false,"visible":false},{"text":"Under electron microscope, the golgi apparatus is supra nuclear in position","correct":false,"visible":false},{"text":"The exocrine portion is composed of compound acinar glands","correct":false,"visible":false},{"text":"Its intercalated ducts open into striated ducts","correct":true,"visible":false}]},{"id":3170,"text":"The thyroid hormone is transported in the blood bound to which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 944.","responses":[{"text":"Corticotropin","correct":false,"visible":false},{"text":"Plasmin","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false},{"text":"Thyroglobulin","correct":false,"visible":false},{"text":"Thyroid binding globulins","correct":true,"visible":false}]},{"id":3176,"text":"What is incorrect regarding the major pancreatic duct?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 489.","responses":[{"text":"It runs all the way from the tail","correct":false,"visible":false},{"text":"It has one branch into the minor pancreatic duct","correct":false,"visible":false},{"text":"It drains the uncinate process","correct":false,"visible":false},{"text":"It opens into the duodenum as the minor duodenal papilla","correct":true,"visible":false},{"text":"It combines with the bile duct to from the hepatopancreatic ampulla","correct":false,"visible":false}]},{"id":3177,"text":"Which of the following is the confirmatory test for acromegaly?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1071.","responses":[{"text":"Insulin levels","correct":false,"visible":false},{"text":"Somatostatin levels","correct":false,"visible":false},{"text":"IGF-1 levels","correct":false,"visible":false},{"text":"Growth hormone levels","correct":false,"visible":false},{"text":"Glucose tolerance test","correct":true,"visible":false}]},{"id":3207,"text":"What is the effect of aldosterone on sweat glands and salivary glands?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 960.","responses":[{"text":"Releasing NaCl only","correct":false,"visible":false},{"text":"Absorbing NaCl only","correct":false,"visible":false},{"text":"Absorbing K and releasing NaCl out of the cell","correct":false,"visible":false},{"text":"Absorbing K only","correct":false,"visible":false},{"text":"Absorbing NaCl and releasing K out of the cell","correct":true,"visible":false}]},{"id":3217,"text":"Which of the following cells are not present in the parenchyma of the parathyroid gland?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 430, 432-434.","responses":[{"text":"Lymphocytes","correct":false,"visible":false},{"text":"Oxyphil cells","correct":false,"visible":false},{"text":"C cells","correct":true,"visible":false},{"text":"Adipose cells","correct":false,"visible":false},{"text":"Chief cells","correct":false,"visible":false}]},{"id":3234,"text":"A 35-year-old lady is diagnosed with autoimmune hypothyroidism. Her physician is concerned about thyroid autoantibodies. Which of the following is the most appropriate antibody to detect autoimmune thyroid disease?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 163.","responses":[{"text":"Anticytoplasmic","correct":false,"visible":false},{"text":"Antiperoxidase","correct":true,"visible":false},{"text":"Antifollicular","correct":false,"visible":false},{"text":"Anti-membrane","correct":false,"visible":false},{"text":"Antinuclear","correct":false,"visible":false}]},{"id":3237,"text":"A 1-year-old boy is brought to the outpatient department with an abnormal opening along the anterior border of the sternocleidomastoid muscle in the inferior third of the neck and discharge of mucus from it is observed. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 164.","responses":[{"text":"Cervical sinus","correct":true,"visible":false},{"text":"Piriform sinus fistula","correct":false,"visible":false},{"text":"Cervical vestiges","correct":false,"visible":false},{"text":"Cervical cyst","correct":false,"visible":false},{"text":"DiGeorge syndrome","correct":false,"visible":false}]},{"id":3240,"text":"Which of the following is a characteristic of hyperthyroidism?","explanation":"One of the key characteristics of hyperthyroidism is an **increased basal metabolic rate (BMR).** Thyroid hormones, specifically triiodothyronine (T3) and thyroxine (T4), play a critical role in regulating metabolism, and an excess of these hormones results in an accelerated BMR. This increased metabolic rate can lead to weight loss despite increased appetite, which is contrary to increased body weight.\r\n\r\nHyperthyroidism is also associated with tachycardia (increased heart rate) rather than bradycardia, as the excess thyroid hormones can directly affect the heart and cardiovascular system. Patients may also experience heat intolerance, increased sweating, and sensitivity to warm temperatures, which is opposite to intolerance to cold.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1076.","responses":[{"text":"Intolerance to cold","correct":false,"visible":false},{"text":"Increased body weight","correct":false,"visible":false},{"text":"Decreased sweating","correct":false,"visible":false},{"text":"Bradycardia","correct":false,"visible":false},{"text":"Increased basal metabolic rate (BMR)","correct":true,"visible":false}]},{"id":3241,"text":"The adrenal cortex is developmentally derived from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 75.","responses":[{"text":"Endoderm","correct":false,"visible":false},{"text":"Neural crest cell","correct":false,"visible":false},{"text":"Epiblast cell","correct":false,"visible":false},{"text":"Surface ectoderm","correct":false,"visible":false},{"text":"Mesoderm","correct":true,"visible":false}]},{"id":3244,"text":"Which one of the following is a characteristic sign of hyperthyroidism?","explanation":null,"reference":"(1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 346.\r\n\r\n(2) Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1076.","responses":[{"text":"Jerky reflexes","correct":false,"visible":false},{"text":"Slow reflexes","correct":false,"visible":false},{"text":"Fine muscle tremor","correct":true,"visible":false},{"text":"Coarse tremor of muscles","correct":false,"visible":false},{"text":"Bradycardia","correct":false,"visible":false}]},{"id":3246,"text":"What is the major target of glucagon for its action?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 982.","responses":[{"text":"Skeletal muscle","correct":false,"visible":false},{"text":"Adipose tissue","correct":false,"visible":false},{"text":"Brain","correct":false,"visible":false},{"text":"Liver","correct":true,"visible":false},{"text":"Kidney","correct":false,"visible":false}]},{"id":3253,"text":"Chromaffin cells are present in which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 425.","responses":[{"text":"Pancreas","correct":false,"visible":false},{"text":"Zona reticularis","correct":false,"visible":false},{"text":"Zona fasciculata","correct":false,"visible":false},{"text":"Adrenal medulla","correct":true,"visible":false},{"text":"Zona glomerulosa","correct":false,"visible":false}]},{"id":3254,"text":"Which of the following is the principal glucocorticoid in the body?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 955.","responses":[{"text":"Cortisol","correct":true,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Deoxymethasone","correct":false,"visible":false},{"text":"Corticosterone","correct":false,"visible":false}]},{"id":3256,"text":"Which of the following is the obligatory and intermediate lipophilic and hydrophobic hormone in the biosynthesis of both estradiol and dihydrotestosterone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1033.","responses":[{"text":"Testosterone","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Cholesterol","correct":false,"visible":false},{"text":"Pregnenolone","correct":true,"visible":false}]},{"id":3258,"text":"When is zona reticularis developed?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 346.","responses":[{"text":"After birth","correct":true,"visible":false},{"text":"In sixth month of fetal life","correct":false,"visible":false},{"text":"In third month of fetal life","correct":false,"visible":false},{"text":"In ninth month of fetal life","correct":false,"visible":false},{"text":"In fifth month of fetal life","correct":false,"visible":false}]},{"id":3259,"text":"Which of the following is an intermediate in the formation of steroid hormones?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 956.","responses":[{"text":"Prostacyclin","correct":false,"visible":false},{"text":"Progestin","correct":false,"visible":false},{"text":"Proelastase","correct":false,"visible":false},{"text":"Protanope","correct":false,"visible":false},{"text":"Pregnenolone","correct":true,"visible":false}]},{"id":3261,"text":"A second-year medical student, while examining the hypophysis cerebri, noticed some\r\nneurons connecting the hypothalamus to the posterior pituitary. Which of the following nuclei of the hypothalamus are connected to the posterior pituitary gland?","explanation":"The nuclei of the hypothalamus that are connected to the posterior pituitary gland are the **supraoptic nucleus** and the **paraventricular nucleus**.\r\n\r\nThe supraoptic nucleus synthesizes and releases antidiuretic hormone (ADH), also known as vasopressin. ADH is responsible for regulating water balance and preventing excessive water loss in the body. When ADH is released into the bloodstream, it acts on the kidneys, promoting water reabsorption, and reducing urine output.\r\n\r\nThe paraventricular nucleus synthesizes and releases oxytocin. Oxytocin plays a crucial role in uterine contractions during labor and delivery and is also involved in milk ejection during breastfeeding.\r\n\r\nBoth ADH and oxytocin are synthesized in the cell bodies of neurons located in the supraoptic and paraventricular nuclei of the hypothalamus. These neurons send their axons down the hypothalamic-hypophyseal tract to the posterior pituitary gland, where the hormones are stored and later released into the bloodstream when needed.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 930.","responses":[{"text":"Ventromedial and preoptic nuclei","correct":false,"visible":false},{"text":"Supraoptic and suprachiasmatic nuclei","correct":false,"visible":false},{"text":"Paraventricular and preoptic nuclei","correct":false,"visible":false},{"text":"Supraoptic and paraventricular nuclei","correct":true,"visible":false},{"text":"Supraoptic and preoptic nuclei","correct":false,"visible":false}]},{"id":3263,"text":"Which of the following is a function of the parathyroid hormone?","explanation":null,"reference":"(1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1000.\r\n\r\n(2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 338.","responses":[{"text":"Decreases the blood calcium level","correct":false,"visible":false},{"text":"Decreases renal phosphate excretion","correct":false,"visible":false},{"text":"Increases renal calcium excretion","correct":false,"visible":false},{"text":"Increases osteoclastic resorption of bone","correct":true,"visible":false},{"text":"Decreases intestinal absorption of calcium","correct":false,"visible":false}]},{"id":3264,"text":"A 40-year-old lady comes to the outpatient department with a painful swelling on the neck. She has high T3 and T4 and her TSH is diminished. The thyroid gland is tender and palpable. What is the most likely cause of her thyrotoxicosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1080-1081.","responses":[{"text":"Hashimoto's thyroiditis","correct":false,"visible":false},{"text":"Multinodular goiter","correct":false,"visible":false},{"text":"Graves disease","correct":false,"visible":false},{"text":"Granulomatous (de Quervain) thyroiditis","correct":true,"visible":false},{"text":"Iodine induced hyperthyroidism","correct":false,"visible":false}]},{"id":3268,"text":"A patient presented to the clinic with the symptoms of hyperthyroidism. Which of the following should be assessed to confirm the diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1077.","responses":[{"text":"Thyroglobulin","correct":false,"visible":false},{"text":"T4","correct":false,"visible":false},{"text":"TSH","correct":true,"visible":false},{"text":"Free T3","correct":false,"visible":false},{"text":"TRH","correct":false,"visible":false}]},{"id":3273,"text":"Which of the following stimulates growth hormone production?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 933.","responses":[{"text":"High blood free fatty acids","correct":false,"visible":false},{"text":"Somatostatin","correct":false,"visible":false},{"text":"Low protein diet","correct":false,"visible":false},{"text":"Estrogen","correct":true,"visible":false},{"text":"High blood glucose","correct":false,"visible":false}]},{"id":3274,"text":"A 30-year-old woman presents to the outpatient department with pain in the lower abdomen and has passed three stones in the urine. She also has high calcium and low phosphate levels in her blood. What is the diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 165.","responses":[{"text":"Chronic renal failure","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Osteogenesis imperfecta","correct":false,"visible":false},{"text":"Paget's disease","correct":false,"visible":false},{"text":"Osteitis fibrosa cystica","correct":true,"visible":false}]},{"id":3279,"text":"Normal growth hormone (GH) levels leads to the formation of which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 935.","responses":[{"text":"GHRH","correct":false,"visible":false},{"text":"Somatostatin","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Somatomedin","correct":true,"visible":false},{"text":"Prolactin","correct":false,"visible":false}]},{"id":3280,"text":"What is the action of insulin on carbohydrate metabolism in muscles?","explanation":null,"reference":"Dow Lecture slides: Endocrinology module, Subject: Physiology, Topic: Glucose Homeostasis, Sub-topic: Which organs require Insulin for Glucose to enter.","responses":[{"text":"Decreased glycogen synthesis","correct":false,"visible":false},{"text":"Decreased glucose uptake by GLUT4","correct":false,"visible":false},{"text":"Open potassium channels","correct":false,"visible":false},{"text":"Increased glucose uptake by GLUT4","correct":true,"visible":false},{"text":"Increased glucose uptake by GLUT2","correct":false,"visible":false}]},{"id":3281,"text":"The adrenal medulla is embryologically derived from which of the following?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 78.","responses":[{"text":"Neural crest cell","correct":true,"visible":false},{"text":"Epiblast","correct":false,"visible":false},{"text":"Surface ectoderm","correct":false,"visible":false},{"text":"Mesoderm","correct":false,"visible":false},{"text":"Endoderm","correct":false,"visible":false}]},{"id":3282,"text":"In a histologic section, there are numerous large, water-clear cells among cuboidal cells. Which type of cells are these clear cells?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 430.","responses":[{"text":"Follicular cells","correct":false,"visible":false},{"text":"Oxyphil cells","correct":false,"visible":false},{"text":"Parafollicular cells","correct":true,"visible":false},{"text":"Chief cells","correct":false,"visible":false},{"text":"Principal cells","correct":false,"visible":false}]},{"id":3285,"text":"Glucagon is synthesized as a prohormone in which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 973","responses":[{"text":"C cells","correct":false,"visible":false},{"text":"Chief cells","correct":false,"visible":false},{"text":"Delta cells","correct":false,"visible":false},{"text":"Alpha cells","correct":true,"visible":false},{"text":"Beta cells","correct":false,"visible":false}]},{"id":3286,"text":"Diabetes insipidus is caused by deficiency of which hormone?","explanation":"Diabetes insipidus (DI) is a disorder characterized by excessive thirst and the production of large volumes of dilute urine. It is caused by the deficiency or inadequate action of **antidiuretic hormone (ADH)**, also known as vasopressin. ADH is produced by the hypothalamus and released by the posterior pituitary gland in response to low blood volume or increased plasma osmolality.\r\n\r\nThe primary function of ADH is to regulate water balance by increasing water reabsorption in the kidney's collecting ducts, leading to the concentration of urine and the preservation of body water. In diabetes insipidus, the lack of ADH leads to the failure of the kidneys to reabsorb water properly, resulting in the excretion of large volumes of dilute urine and causing dehydration and excessive thirst.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 938-939.","responses":[{"text":"ADH","correct":true,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Angiotensin II","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"FSH","correct":false,"visible":false}]},{"id":3287,"text":"Which of the following is the carrier protein for thyroid hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 944.","responses":[{"text":"Thyroxine-binding globulin","correct":true,"visible":false},{"text":"Fibrinogen","correct":false,"visible":false},{"text":"Transthyretin","correct":false,"visible":false},{"text":"Sex-hormone binding globulin","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false}]},{"id":3288,"text":"Type I diabetes is associated with which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1099.","responses":[{"text":"Autoimmunity","correct":true,"visible":false},{"text":"Metabolic syndrome","correct":false,"visible":false},{"text":"Smoking","correct":false,"visible":false},{"text":"Obesity","correct":false,"visible":false},{"text":"Excess growth hormone","correct":false,"visible":false}]},{"id":3289,"text":"The superior parathyroid gland develops from which pharyngeal pouch?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 163.","responses":[{"text":"4th","correct":true,"visible":false},{"text":"5th","correct":false,"visible":false},{"text":"3rd","correct":false,"visible":false},{"text":"2nd","correct":false,"visible":false},{"text":"1st","correct":false,"visible":false}]},{"id":3292,"text":"The inferior thyroid artery is a branch of which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1008.","responses":[{"text":"Internal carotid artery","correct":false,"visible":false},{"text":"Arch of aorta","correct":false,"visible":false},{"text":"Superior thyroid artery","correct":false,"visible":false},{"text":"Thyro-cervical trunk","correct":true,"visible":false},{"text":"Internal thoracic trunk","correct":false,"visible":false}]},{"id":3320,"text":"Cortisol is which class of substance?","explanation":null,"reference":"Ramamoorthy S, Cidlowski JA. Corticosteroids-mechanisms of action in health and disease. Rheumatic diseases clinics of North America. Published February 2016. Accessed July 3, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4662771/","responses":[{"text":"Natural mineralocorticoid","correct":false,"visible":false},{"text":"Natural glucocorticoid","correct":true,"visible":false},{"text":"Synthetic glucocorticoid","correct":false,"visible":false},{"text":"Synthetic mineralocorticoid","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3321,"text":"What is the normal plasma calcium concentration?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 991.","responses":[{"text":"69-71 mg/dL","correct":false,"visible":false},{"text":"2.2–2.6 mg/dL","correct":false,"visible":false},{"text":"9-11 mg/dL","correct":true,"visible":false},{"text":"19-21 mg/dL","correct":false,"visible":false},{"text":"17-19 mg/dL","correct":false,"visible":false}]},{"id":3322,"text":"Which of the following types of cells are majorly placed centrally in the pancreas?","explanation":"The pancreas is a gland located in the abdomen, and it plays a crucial role in the regulation of blood glucose levels. It contains various types of cells, each responsible for the secretion of specific hormones. The two major types of cells found in the pancreas are alpha cells and beta cells.\r\n\r\n1. **Alpha cells:** These cells are primarily located in the periphery of the islets of Langerhans in the pancreas. They secrete the hormone glucagon, which helps raise blood glucose levels by promoting the breakdown of glycogen in the liver and the release of glucose into the bloodstream.\r\n\r\n2. **Beta cells:** These cells are centrally placed within the islets of Langerhans in the pancreas. They are responsible for producing and releasing the hormone insulin. Insulin plays a key role in lowering blood glucose levels by facilitating the uptake of glucose by cells, especially in muscles and adipose tissue.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427.","responses":[{"text":"Delta cells","correct":false,"visible":false},{"text":"Alpha cells","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Beta cells","correct":true,"visible":false},{"text":"PP cells","correct":false,"visible":false}]},{"id":3335,"text":"What is true regarding blood supply to the adrenal gland?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 424.","responses":[{"text":"Zona fasciculata has dual blood supply","correct":false,"visible":false},{"text":"The blood first passes through the kidneys","correct":false,"visible":false},{"text":"Adrenal medulla has both arterial and venous blood supply","correct":true,"visible":false},{"text":"Blood flows from the medulla to the cortex","correct":false,"visible":false},{"text":"Blood is supplied by sinusoids only","correct":false,"visible":false}]},{"id":3338,"text":"What differentiates the pancreas from the parotid gland?","explanation":"The key difference that sets the pancreas apart from the parotid gland is the **presence of centroacinar cells and absence of striated ducts** in the pancreas.\r\n\r\n1. **Centroacinar cells**: These are specialized cells found in the **center of acini** (clusters of secretory cells) in the pancreas. They play an essential role in the production of pancreatic enzymes. These enzymes are initially synthesized in the rough endoplasmic reticulum of acinar cells and are then transported through the centroacinar cells into the pancreatic duct system.\r\n\r\n2. **Striated ducts**: These are a distinctive feature of the parotid gland. Striated ducts have extensive infoldings of the basal cell membrane, which gives them a \"striated\" appearance. They are involved in modifying the primary saliva by reabsorbing sodium and chloride ions and secreting potassium and bicarbonate ions.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 333.","responses":[{"text":"Secretory cells arranged in a circle around a central duct in the pancreas","correct":false,"visible":false},{"text":"Presence of striated ducts in the pancreas","correct":false,"visible":false},{"text":"Compound glands are present in the pancreas","correct":false,"visible":false},{"text":"Presence of centroacinar cells and absence of striated ducts in the pancreas","correct":true,"visible":false},{"text":"Serous acini are present in the parotid, not in the pancreas","correct":false,"visible":false}]},{"id":3340,"text":"Which of the following is not necessary for thyroid hormone secretion?","explanation":null,"reference":null,"responses":[{"text":"Iodine","correct":false,"visible":false},{"text":"Peroxidase enzyme","correct":false,"visible":false},{"text":"Tyrosine","correct":false,"visible":false},{"text":"Ferritin","correct":true,"visible":false},{"text":"Thyroglobulin","correct":false,"visible":false}]},{"id":3341,"text":"Which of the following is a metabolic complication arising from insulin-dependent diabetes?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1101.","responses":[{"text":"Absolute deficiency of insulin","correct":true,"visible":false},{"text":"Insulin toxicity","correct":false,"visible":false},{"text":"Relative deficiency of insulin","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Both relative and absolute deficiency of insulin","correct":false,"visible":false}]},{"id":3350,"text":"Which of the following is incorrect about oxyphil cells?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 434.","responses":[{"text":"They have eosinophilic cytoplasm","correct":false,"visible":false},{"text":"Their number increases with age","correct":false,"visible":false},{"text":"They are arranged in small clusters","correct":false,"visible":false},{"text":"They play a major role in calcium homeostasis","correct":true,"visible":false},{"text":"They are bigger in size than principal cells","correct":false,"visible":false}]},{"id":3351,"text":"While examining the adrenal gland in a newborn baby, only two zones are seen while zona reticularis is absent. What is the reason for its absence?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 346.","responses":[{"text":"Zona reticularis is present only in 1 percent population","correct":false,"visible":false},{"text":"There are only two zones in adrenal gland and zona reticularis does not exist","correct":false,"visible":false},{"text":"Specific staining techniques are required to observe zona reticularis","correct":false,"visible":false},{"text":"It is a congenital defect","correct":false,"visible":false},{"text":"Zona reticularis is developed after birth","correct":true,"visible":false}]},{"id":3352,"text":"A hypothyroid patient is treated with thyroxine. How frequently should a thyroid function test be repeated?","explanation":null,"reference":"Dow Lecture slides: Endocrinology module, Subject: Medicine, Topic: Presentation of Hypo/hyperthyroidism, Sub-topic: Management of Hypothyroidism","responses":[{"text":"2 week interval","correct":false,"visible":false},{"text":"1 month interval","correct":true,"visible":false},{"text":"6 month interval","correct":false,"visible":false},{"text":"1 year interval","correct":false,"visible":false},{"text":"3 month interval","correct":false,"visible":false}]},{"id":3353,"text":"In diabetes mellitus, insulin deficiency causes which of the following effect?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 977.","responses":[{"text":"Increased uptake of glucose by muscles","correct":false,"visible":false},{"text":"Decreased alpha glycerol phosphate in fat cells","correct":true,"visible":false},{"text":"Inhibition of hormone sensitive lipase","correct":false,"visible":false},{"text":"Decreased glucose in blood","correct":false,"visible":false},{"text":"Increased rate of glycogen synthesis","correct":false,"visible":false}]},{"id":3354,"text":"Which of the following drugs can cause drug-induced hypothyroidism?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 647.","responses":[{"text":"Nivolumab","correct":false,"visible":false},{"text":"Amiodarone","correct":true,"visible":false},{"text":"Alemtuzumab","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Pembrolizumab","correct":false,"visible":false}]},{"id":3355,"text":"There is increased uptake of radioactive iodine in a solitary area of the thyroid gland. What is most likely present in that area?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1085.","responses":[{"text":"Thyroglossal cyst","correct":false,"visible":false},{"text":"Toxic adenoma","correct":true,"visible":false},{"text":"Pheochromocytoma","correct":false,"visible":false},{"text":"Colloid nodule","correct":false,"visible":false},{"text":"Follicular carcinoma","correct":false,"visible":false}]},{"id":3356,"text":"A 10-year-old-girl is brought to the emergency room in a semi-conscious state with a complaint of abdominal pain for the past 10 hours. On examination, she is visibly drowsy and has a peculiar fruity smell in her breath. What is the most likely cause to be considered in this case?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1106.","responses":[{"text":"Starvation ketosis","correct":false,"visible":false},{"text":"Salicylate poisoning","correct":false,"visible":false},{"text":"Sepsis","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Acute renal failure","correct":false,"visible":false}]},{"id":3357,"text":"Why is insulin administered in diabetic ketoacidosis?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 975.","responses":[{"text":"To stimulate ketone utilization in brain tissue","correct":false,"visible":false},{"text":"To decrease glucose uptake by liver","correct":false,"visible":false},{"text":"To decrease glucose uptake by fat cells","correct":false,"visible":false},{"text":"To increase glucose uptake by muscle","correct":true,"visible":false},{"text":"To destroy ketone bodies","correct":false,"visible":false}]},{"id":3358,"text":"What is the most common cause of Addison's disease in the West?","explanation":"Addison's disease, also known as primary adrenal insufficiency, is a condition characterized by the inadequate production of hormones by the adrenal glands. In the Western world, the most common cause of Addison's disease is autoimmune adrenalitis.\r\n\r\n**Autoimmune adrenalitis** occurs when the body's immune system mistakenly attacks and destroys the adrenal glands. This leads to a progressive loss of adrenal function and a decrease in the production of essential hormones, such as cortisol and aldosterone. Over time, the adrenal glands become smaller and may show signs of chronic inflammation.\r\n\r\nWhile tuberculosis used to be a common cause of Addison's disease in the past, particularly in developing countries, it has become less prevalent in the Western world due to improved healthcare and antibiotic treatments. Tumors of the adrenal gland, congenital absence of the adrenal gland, and infections are relatively rare causes of primary adrenal insufficiency compared to autoimmune adrenalitis.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1123.","responses":[{"text":"Autoimmune adrenalitis","correct":true,"visible":false},{"text":"Tumor of adrenal gland","correct":false,"visible":false},{"text":"Infection","correct":false,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Congenital absence of adrenal gland","correct":false,"visible":false}]},{"id":3364,"text":"Pheochromocytoma is a tumor of which cell type?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 172.","responses":[{"text":"Chromaffin cells","correct":true,"visible":false},{"text":"Parafollicular C cells","correct":false,"visible":false},{"text":"Islets of Langerhans","correct":false,"visible":false},{"text":"Delta cells","correct":false,"visible":false},{"text":"Neural crest cells","correct":false,"visible":false}]},{"id":3365,"text":"Which of the following is confirmatory for pheochromocytoma?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1129.","responses":[{"text":"Increased T4 levels","correct":false,"visible":false},{"text":"Increased vanillylmandelic acid (VMA) and homovanillic acid (HVA) levels","correct":true,"visible":false},{"text":"High serum calcium levels","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Charcot-leyden crystals","correct":false,"visible":false}]},{"id":3366,"text":"Which of the following test should be performed for pheochromocytoma?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1129.","responses":[{"text":"Buccal smear test","correct":false,"visible":false},{"text":"Test for catecholamines","correct":true,"visible":false},{"text":"Barr body test","correct":false,"visible":false},{"text":"Serum urea","correct":false,"visible":false},{"text":"Serum creatinine","correct":false,"visible":false}]},{"id":3367,"text":"Centroacinar cells are present in which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 333.","responses":[{"text":"Parathyroid glands","correct":false,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Thyroid gland","correct":false,"visible":false},{"text":"Endocrine part of the pancreas","correct":false,"visible":false},{"text":"Exocrine part of the pancreas","correct":true,"visible":false}]},{"id":3368,"text":"Islets of Langerhans are mostly located in which portion of the pancreas?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427.","responses":[{"text":"Head of the pancreas","correct":false,"visible":false},{"text":"Centroacinar cells","correct":false,"visible":false},{"text":"Uncinate process","correct":false,"visible":false},{"text":"Body of the pancreas","correct":false,"visible":false},{"text":"Tail of the pancreas","correct":true,"visible":false}]},{"id":3369,"text":"Which of the following is incorrect regarding the parathyroid gland?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 430.","responses":[{"text":"Contains lymphocytes","correct":false,"visible":false},{"text":"Derived from the third and fourth pharyngeal pouches","correct":false,"visible":false},{"text":"It has chief cells that secrete PTH","correct":false,"visible":false},{"text":"It has C-cells","correct":true,"visible":false},{"text":"Secretes PTH in response to decreased calcium","correct":false,"visible":false}]},{"id":3372,"text":"A student observes a slide of tissue in which oval masses of cells and fenestrated capillaries can be observed. Four types of secretory cells can be recognized in this tissue. Which structure is present on this slide?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427, 429.","responses":[{"text":"Islets of langerhans","correct":true,"visible":false},{"text":"C-cells","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Follicular cells","correct":false,"visible":false},{"text":"Oxyphil cells","correct":false,"visible":false}]},{"id":3373,"text":"Which of the following leads to the secretion of insulin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 979.","responses":[{"text":"Closure of potassium channels which leads to potassium accumulation in beta cell","correct":true,"visible":false},{"text":"Opening of potassium channels which leads to potassium deficiency in beta cell","correct":false,"visible":false},{"text":"Closure of both sodium and potassium channels","correct":false,"visible":false},{"text":"Opening of sodium channels which leads to sodium outflow from beta cell","correct":false,"visible":false},{"text":"Closure of sodium channels which leads to sodium accumulation in beta cell","correct":false,"visible":false}]},{"id":3374,"text":"Decreased tissue response to the parathyroid hormone is seen in which of the following condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1097.","responses":[{"text":"Pseudohypoparathyroidism","correct":true,"visible":false},{"text":"Congenital absence of parathyroid gland","correct":false,"visible":false},{"text":"Primary hypoparathyroidism","correct":false,"visible":false},{"text":"Secondary hypoparathyroidism","correct":false,"visible":false},{"text":"Acquired hypoparathyroidism","correct":false,"visible":false}]},{"id":3375,"text":"Which of the following may result as a complication of low levels of aldosterone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 960.","responses":[{"text":"Hypovolemic shock","correct":false,"visible":false},{"text":"Weak heart contractions, arrhythmia, and cardiac failure","correct":true,"visible":false},{"text":"Strong heart contractions, arrhythmia, and cardiac failure","correct":false,"visible":false},{"text":"Strong heart contractions and tachycardia","correct":false,"visible":false},{"text":"Adrenal crisis","correct":false,"visible":false}]},{"id":3376,"text":"A patient is suffering from diabetic ketoacidosis. He is admitted to the hospital and is undergoing insulin therapy. Which of the following should be regularly monitored in the patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1107.","responses":[{"text":"Blood insulin levels","correct":false,"visible":false},{"text":"Glucose levels in urine","correct":false,"visible":false},{"text":"HbA1c","correct":false,"visible":false},{"text":"Blood glucose levels","correct":true,"visible":false},{"text":"Levels of ketone bodies in blood","correct":false,"visible":false}]},{"id":3377,"text":"What should be the treatment for a patient with diabetic ketoacidosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1106.","responses":[{"text":"Balanced diet and insulin","correct":false,"visible":false},{"text":"High protein diet and insulin","correct":false,"visible":false},{"text":"Oral hypoglycemic drugs","correct":false,"visible":false},{"text":"Low fat diet and insulin","correct":false,"visible":false},{"text":"Diabetic diet and insulin","correct":true,"visible":false}]},{"id":3378,"text":"Cortisol decreases the production of which of the following cell lines?","explanation":null,"reference":"Yasir M, Goyal A, Sonthalia S. Corticosteroid adverse effects. In: StatPearls. StatPearls Publishing; 2022. Accessed July 4, 2022. http://www.ncbi.nlm.nih.gov/books/NBK531462/","responses":[{"text":"Eosinophils","correct":true,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Red blood cells","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false},{"text":"Neutrophils","correct":false,"visible":false}]},{"id":3379,"text":"Cortisol increases the production of which of the following cell lines?","explanation":null,"reference":"Yasir M, Goyal A, Sonthalia S. Corticosteroid adverse effects. In: StatPearls. StatPearls Publishing; 2022. Accessed July 4, 2022. http://www.ncbi.nlm.nih.gov/books/NBK531462/","responses":[{"text":"Platelets","correct":false,"visible":false},{"text":"Eosinophils","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Monocytes","correct":false,"visible":false},{"text":"Neutrophils","correct":true,"visible":false}]},{"id":3380,"text":"Which of the following is incorrect regarding anterior pituitary?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917-918.","responses":[{"text":"Produces TSH, FSH, LH, ACTH, and prolactin","correct":false,"visible":false},{"text":"Produces tropic homones only","correct":true,"visible":false},{"text":"Does not prodcue ADH and oxytocin","correct":false,"visible":false},{"text":"It is known as the adenohypophysis","correct":false,"visible":false},{"text":"Produces tropic and direct-acting hormones","correct":false,"visible":false}]},{"id":3381,"text":"Hypoaldosteronism results in which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 960.","responses":[{"text":"Hypokalemia","correct":false,"visible":false},{"text":"Hypercalcemia","correct":false,"visible":false},{"text":"Hyperlycemia","correct":false,"visible":false},{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Hyperkalemia","correct":true,"visible":false}]},{"id":3382,"text":"Neurohypophysis stores which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 938.","responses":[{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Follicle-stimulating hormone (FSH)","correct":false,"visible":false},{"text":"Luteinizing hormone (LH)","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Antidiuretic hormone (ADH)","correct":true,"visible":false}]},{"id":3384,"text":"A 32-year-old patient presented with a raised heart rate, profuse sweating, palpitations, and restlessness 2 months ago. His serum T3 and T4 were high and TSH was low. He had been getting treatment for his condition since then. Which follow-up tests should be performed?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 656.","responses":[{"text":"TRH levels","correct":false,"visible":false},{"text":"Serum T3 and T4 levels","correct":false,"visible":false},{"text":"Repeat TSH","correct":false,"visible":false},{"text":"Repeat TSH and serum T3 and T4 levels","correct":true,"visible":false},{"text":"Free serum T3","correct":false,"visible":false}]},{"id":3415,"text":"Which of the following is inappropriate regarding the pancreas?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 332, 427.","responses":[{"text":"The exocrine part of the pancreas is similar to the parotid gland","correct":false,"visible":false},{"text":"Rough endoplasmic reticulum is abundant in serous cells","correct":false,"visible":false},{"text":"Serous cells contain spherical nuclei","correct":false,"visible":false},{"text":"It contain both endocrine and exocrine parts","correct":false,"visible":false},{"text":"The endocrine part of the pancreas is similar to the parotid gland","correct":true,"visible":false}]},{"id":3416,"text":"A middle-aged man presents to the outpatient department with mild hypothermia. A physical examination reveals goiter, sparse hair, ptosis, and non-pitting edema. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1078.","responses":[{"text":"Acromegaly","correct":false,"visible":false},{"text":"Myxedema","correct":true,"visible":false},{"text":"Multinodular goiter","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Cretinism","correct":false,"visible":false}]},{"id":3417,"text":"Which of the following is responsible for aldosterone secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 956.","responses":[{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Angiotensin II","correct":true,"visible":false},{"text":"Angiotensinogen","correct":false,"visible":false},{"text":"Angiotensin I","correct":false,"visible":false}]},{"id":3419,"text":"Which hormone increases the absorption of calcium from intestines?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1001.","responses":[{"text":"Parathyroid hormone","correct":true,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Calcitonin","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Vasopressin","correct":false,"visible":false}]},{"id":3455,"text":"What is the prohormone of glucagon called?","explanation":null,"reference":"Rouillé Y, Westermark G, Martin SK, Steiner DF. Proglucagon is processed to glucagon by prohormone convertase PC2 in alpha TC1-6 cells. Proc Natl Acad Sci U S A. 1994;91(8):3242-3246. Accessed July 4, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC43552/","responses":[{"text":"Proglucagon","correct":true,"visible":false},{"text":"Glucagonogen","correct":false,"visible":false},{"text":"Glucagon prohormone","correct":false,"visible":false},{"text":"Glucagonin","correct":false,"visible":false},{"text":"Preglucagon","correct":false,"visible":false}]},{"id":3456,"text":"In beta cells of the pancreas, glucose is phosphorylated by which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 979.","responses":[{"text":"Glycogen phosphorylase","correct":false,"visible":false},{"text":"Hexokinase","correct":false,"visible":false},{"text":"Glucose kinase","correct":false,"visible":false},{"text":"Glucokinase","correct":true,"visible":false},{"text":"Insulin receptor","correct":false,"visible":false}]},{"id":3457,"text":"Where is the pituitary gland present relative to the optic chiasm?","explanation":null,"reference":"Ireland AC, Carter IB. Neuroanatomy, optic chiasm. In: StatPearls. StatPearls Publishing; 2022. Accessed July 4, 2022. http://www.ncbi.nlm.nih.gov/books/NBK542287/","responses":[{"text":"Anteriorly","correct":false,"visible":false},{"text":"Superiorly","correct":false,"visible":false},{"text":"Inferiorly","correct":true,"visible":false},{"text":"Posteriorly","correct":false,"visible":false},{"text":"Laterally","correct":false,"visible":false}]},{"id":3458,"text":"A 37-year-old female who had a kidney transplant two months ago is currently on immunosuppressants and corticosteroids. She suddenly stops taking prednisone. This puts her at an increased risk of developing which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1122.","responses":[{"text":"Nausea","correct":false,"visible":false},{"text":"Opportunistic infections","correct":false,"visible":false},{"text":"Adrenal crisis","correct":true,"visible":false},{"text":"Hemolytic anemia","correct":false,"visible":false},{"text":"Hyperaldosteronism","correct":false,"visible":false}]},{"id":3459,"text":"Which of the following diseases affects both mineralocorticoid and glucocorticoid secretion?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1124.","responses":[{"text":"Pheochromocytoma","correct":false,"visible":false},{"text":"Waterhouse-Friderichsen syndrome","correct":false,"visible":false},{"text":"Cushing syndrome","correct":false,"visible":false},{"text":"Conn syndrome","correct":false,"visible":false},{"text":"Addison disease","correct":true,"visible":false}]},{"id":3460,"text":"Parathyroid adenoma is most commonly associated with which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1094.","responses":[{"text":"MEN-1","correct":true,"visible":false},{"text":"Parathyroid carcinoma","correct":false,"visible":false},{"text":"Hypoparathyriodism","correct":false,"visible":false},{"text":"MEN-2","correct":false,"visible":false},{"text":"Secondary hyperparathyriodism","correct":false,"visible":false}]},{"id":3493,"text":"A person with cardiovascular disease wants to decrease his low-density lipoprotein (LDL) cholesterol level. What would be the preferred suggestion?","explanation":"The preferred suggestion for a person with cardiovascular disease who wants to decrease their low-density lipoprotein (LDL) cholesterol level is **statins**.\r\n\r\nStatins, also known as HMG-CoA reductase inhibitors, are a class of drugs that effectively lower LDL cholesterol levels in the blood. They work by inhibiting the enzyme HMG-CoA reductase, which is involved in cholesterol synthesis. By reducing cholesterol production in the liver, statins lead to increased uptake and clearance of LDL cholesterol from the bloodstream, resulting in decreased LDL levels.\r\n\r\nNiacin and fibrates are also used to modify lipid levels, but they primarily target triglycerides and HDL cholesterol rather than LDL cholesterol. Exercise and weight loss can have some positive effects on cholesterol levels, but they are generally not as potent as statins in lowering LDL cholesterol and are often recommended as complementary lifestyle measures alongside medication.\r\n\r\nFor individuals with cardiovascular disease, statins are the first-line treatment to reduce LDL cholesterol and lower the risk of cardiovascular events.","reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 290.","responses":[{"text":"Niacin","correct":false,"visible":false},{"text":"Weight loss","correct":false,"visible":false},{"text":"Fibrates","correct":false,"visible":false},{"text":"Statins","correct":true,"visible":false},{"text":"Exercise","correct":false,"visible":false}]},{"id":3793,"text":"Which of the following approaches should not be used for stress management?","explanation":null,"reference":"Dow Lecture slides: Endocrinology module, Subject: Behavioral Sciences, Topic: Stress Management, Sub-topic: Stress Management Techniques","responses":[{"text":"Exercise","correct":false,"visible":false},{"text":"Venting your emotions","correct":false,"visible":false},{"text":"Identifying triggers","correct":false,"visible":false},{"text":"Coping skills","correct":false,"visible":false},{"text":"Aggression","correct":true,"visible":false}]},{"id":4877,"text":"Which of the following artery supplies blood to the pancreas?","explanation":"The pancreas receives its blood supply primarily from the **splenic artery**, a branch of the **celiac trunk**. The celiac trunk is a major branch of the abdominal aorta that supplies blood to various organs in the upper abdomen, including the liver, stomach, spleen, and pancreas.\r\n\r\nThe splenic artery courses along the upper border of the pancreas and then divides into multiple smaller branches within the pancreas itself. These branches form an intricate network of blood vessels that supply the various parts of the pancreas.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 491.","responses":[{"text":"Left gastric artery","correct":false,"visible":false},{"text":"Inferior mesenteric artery","correct":false,"visible":false},{"text":"Inferior esophageal artery","correct":false,"visible":false},{"text":"Splenic artery","correct":true,"visible":false},{"text":"Cystic artery","correct":false,"visible":false}]},{"id":8656,"text":"What is the marked macrovascular complication of type 2 diabetes mellitus?","explanation":"Type 2 diabetes mellitus is a metabolic disorder characterized by insulin resistance and impaired insulin secretion. It can lead to various complications, both microvascular and macrovascular, due to the chronic hyperglycemia and associated metabolic disturbances.\r\n\r\n**Macrovascular complications** involve large blood vessels and are major contributors to morbidity and mortality in individuals with type 2 diabetes. **Accelerated atherosclerosis** is a significant macrovascular complication observed in diabetes. Atherosclerosis is the buildup of fatty plaques in the arterial walls, leading to narrowing and hardening of the blood vessels.\r\n\r\nIn patients with type 2 diabetes, chronic high blood glucose levels can damage blood vessels and promote the development of atherosclerosis at an accelerated rate. This increases the risk of **coronary artery disease**, **stroke**, and **peripheral vascular disease**.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1107.","responses":[{"text":"Accelerated arthritis","correct":false,"visible":false},{"text":"Diminishing vision","correct":false,"visible":false},{"text":"Tunnel vision","correct":false,"visible":false},{"text":"Accelerated atherosclerosis","correct":true,"visible":false},{"text":"Retinal vein occlusion","correct":false,"visible":false}]},{"id":13985,"text":"Syndrome of inappropriate antidiuretic hormone secretion is an endocrine disorder that can present with which of the following abnormalities of water homeostasis?","explanation":null,"reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 624, 626","responses":[{"text":"Hypovolemia","correct":false,"visible":false},{"text":"Hyperosmolality","correct":false,"visible":false},{"text":"Hypervolemia","correct":false,"visible":false},{"text":"Euvolemic hypernatremia","correct":false,"visible":false},{"text":"Euvolemic hyponatremia","correct":true,"visible":false}]},{"id":13990,"text":"A 32-year-old female, P1+0, who recently gave birth presents to the clinic with the inability to lactate, headaches, dizziness, and tachycardia. \r\nLaboratory investigations show low serum prolactin levels. \r\nLow to normal levels of prolactin levels are seen in which of the following conditions?","explanation":null,"reference":"First Aid for the USMLE Step 1, 2022, page 345","responses":[{"text":"Pregnancy","correct":false,"visible":false},{"text":"Multiple endocrine neoplasia type 1","correct":false,"visible":false},{"text":"Pituitary infarct","correct":true,"visible":false},{"text":"Pituitary adenoma","correct":false,"visible":false},{"text":"Base of Skull Fracture","correct":false,"visible":false}]},{"id":14251,"text":"A 50-year-old male with Diabetes Mellitus comes to the clinic for a regular medical checkup. On examination, the patient has a BMI of 29, bilateral and yellow plaques on the eyelids. \r\n\r\n\r\nThe physician orders a lipid panel to check for blood levels of LDL-C and triglycerides. \r\nIf reports show an increase in LDL-C, which of the following drugs should the patient be started on?","explanation":null,"reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 640","responses":[{"text":"Ezetimibe","correct":false,"visible":false},{"text":"Bezafibrate","correct":false,"visible":false},{"text":"Atorvastatin","correct":true,"visible":false},{"text":"Alirocumab","correct":false,"visible":false},{"text":"Fenofibrate","correct":false,"visible":false}]},{"id":14252,"text":"A 34-year-old woman presents to the outpatient department for a check-up 1 year after she had been prescribed fenofibrate for a medical condition that causes deranged lipid profiles. She tells you that she often forgets to take her medication. \r\n\r\nFurthermore, she tells you that her maternal uncles have deranged lipid profiles for which they take medications. \r\n\r\nOn physical examination, her height is 5'4\" (163 cm), weight is 82 kg (180 pounds) and BMI is 31.6. She has bilateral yellow plaques on her eyelids and nodular, firm, painless swellings on the extensor surfaces of her hands. \r\n\r\nLaboratory studies are significant for triglycerides = 1100 mg/dL (12.43 mmol/L).\r\n\r\nWhich of the following conditions is this patient most likely at risk of developing?","explanation":"This is a classic case of familial hypertriglyceridemia.","reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 638","responses":[{"text":"Pancreatitis","correct":true,"visible":false},{"text":"Coronary heart disease","correct":false,"visible":false},{"text":"Hepatitis","correct":false,"visible":false},{"text":"Appendicitis","correct":false,"visible":false},{"text":"Cholelithiasis","correct":false,"visible":false}]},{"id":14355,"text":"A 72-year-old patient, with diabetes mellitus and hypertension, presents to the clinic with complaints of symmetric loss of sensation in distal extremities. \r\nThe loss of sensation was initially only in the lower extremities but has now also started in the upper extremities. She sometimes also experiences a burning sensation in her feet, especially at night. \r\nShe is currently taking metformin, lisinopril, and atorvastatin, but she tells you that she frequently forgets to take her medications. \r\nHer most recent laboratory reports show: fasting blood sugar level = 160 mg/dL and HbA1C= 7.6% \r\n\r\nWhat is the most likely diagnosis for the complaint the patient has presented with?","explanation":null,"reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 750","responses":[{"text":"Mononeuritis multiplex","correct":false,"visible":false},{"text":"Diabetic lumbosacral plexopathy","correct":false,"visible":false},{"text":"Peripheral mononeuropathy","correct":false,"visible":false},{"text":"Chronic inflammatory demyelinating polyneuropathy (CIDP)","correct":false,"visible":false},{"text":"Distal symmetric polyneuropathy","correct":true,"visible":false}]},{"id":14357,"text":"A 35-year-old female presents to the clinic with complaints of palpitations, heat intolerance, unintentional weight loss, and a painful mass in her neck. The pain is increased by swallowing and coughing and radiated to the jaw. On examination, the mass moves upon swallowing and is tender. Her hands are clammy, her heart rate is 98 beats per minute and her blood pressure is 140/110 mmHg. \r\nHer serum TSH is low, free T3 and T4 levels are markedly increased, and ESR is increased. A Radioiodine uptake (RAIU) study shows decreased iodine uptake. \r\n\r\nWhat is the most likely diagnosis of this patient?","explanation":null,"reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 663\r\nRobbins Pathological Basis of Disease, 9th edition, page 1088","responses":[{"text":"Subacute lymphocytic thyroiditis","correct":false,"visible":false},{"text":"Postpartum thyroiditis.","correct":false,"visible":false},{"text":"Subacute granulomatous thyroiditis (De Quervain thyroiditis)","correct":true,"visible":false},{"text":"Grave's disease","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":false,"visible":false}]},{"id":14396,"text":"A 40-year-old patient presents to the clinic with complaints of headache, decreased libido, and frequent episodes of hypoglycemia. He mentions that he has had to increase hat, ring, and shoe sizes twice now. \r\nWhich of the following is most likely his diagnosis?","explanation":null,"reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 698","responses":[{"text":"Acromegaly","correct":true,"visible":false},{"text":"Hurler syndrome (mucopolysaccharidosis type I)","correct":false,"visible":false},{"text":"Hunter syndrome (mucopolysaccharidosis type II)","correct":false,"visible":false},{"text":"β Thalassemia major","correct":false,"visible":false},{"text":"Gigantism","correct":false,"visible":false}]},{"id":14397,"text":"A 40-year-old patient presents to the clinic with complaints of headache, decreased libido, and frequent episodes of hypoglycemia. He mentions that he has had to increase hat, ring, and shoe sizes twice now. \r\nWhich of the following is the single best test to confirm the diagnosis of his condition?","explanation":"The question asks for the SINGLE best test which is serum IGf-1 levels.  The most specific test for diagnosing acromegaly is OGTT with baseline GH and then measuring GH after 1-2 hours. GH suprresion to \u003c0.4 μg is diagnostic. However none of the options mention them both together, and this is not a 'single' test. \r\nOwing to the pulsatility of GH secretion, measurement of a single random GH level is not useful for the diagnosis or exclusion of acromegaly.\r\nIncreased prolactin levels can be seen in approximately 30% of patients but this is not useful in the diagnosis of acromegaly. Rather it is due to the co-secretion of prolactin from the pituitary tumor.","reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 698\r\nHarrison's Principles of Internal Medicine, 20th edition, page 2679","responses":[{"text":"Oral glucose tolerance test","correct":false,"visible":false},{"text":"Serum growth hormone level","correct":false,"visible":false},{"text":"Pituitary MRI","correct":false,"visible":false},{"text":"Serum IGF-1 concentration","correct":true,"visible":false},{"text":"Serum prolactin concentration","correct":false,"visible":false}]},{"id":14422,"text":"A 78-year-old female presents to the family medicine clinic with complaints of ulcers on her foot which are healing poorly and loss of sensation in the distal lower extremities. A monofilament test shows diminished sensation in right lower limb up to her ankles and weak pulses in the dorsalis pedis and posterior tibial arteries of the right lower limb. \r\n\r\nHer most recent laboratory report shows random blood glucose = 218 mg/dL, fasting blood sugar = 188 mg/dL, and HbA1C = 7.8%. \r\n\r\nWhich of the following specialist should this patient be referred to for her presenting complaint?","explanation":null,"reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 752.","responses":[{"text":"Endocrinologist","correct":false,"visible":false},{"text":"Dermatologist","correct":false,"visible":false},{"text":"Neurologist","correct":false,"visible":false},{"text":"Oporthopedist","correct":false,"visible":false},{"text":"Podiatrist","correct":true,"visible":false}]},{"id":20080,"text":"An elderly man is brought to the emergency room with altered levels of consciousness. His initial blood glucose measurement revealed severe hypoglycemia. There is no history of significant weight loss or gain, but he complains of body aches. His insulin levels are high, and his C-peptide levels are low. Family history reveals a 20-year-old son with type-1 diabetes mellitus. What is the most likely cause of hypoglycemia in this elderly patient with altered consciousness?","explanation":null,"reference":"Davidson’s Principles and Practice of Medicine, 24th edition, page 690","responses":[{"text":"Factitious hypoglycemia","correct":true,"visible":false},{"text":"Inadequate dietary intake","correct":false,"visible":false},{"text":"Sulfonylurea ingestion","correct":false,"visible":false},{"text":"Insulinoma","correct":false,"visible":false},{"text":"Alcohol excess","correct":false,"visible":false}]}
]

export default a